options:
mid stealth/.style={
        postaction={
            decorate,
            decoration={
                markings,
                mark=at position 0.5 with {
                    \arrow{Stealth[length=3.2mm,width=3mm]}
                }
            }
        }
    }

vertex/.style={
        circle,
        fill=black,
        inner sep=0pt,
        minimum size=2.5mm
    }

body.code:
% Vertices
\coordinate (BL) at (0,0);
\coordinate (BR) at (5,0);
\coordinate (TR) at (5,5);
\coordinate (TL) at (0,5);
\coordinate (O)  at (2.5,2.5);

% Boundary edges
\draw[mid stealth]
    (TL) -- node[midway,above=4pt] {$a$} (TR);

\draw[mid stealth]
    (BL) -- node[midway,below=4pt] {$a$} (BR);

\draw[mid stealth]
    (BL) -- node[midway,left=4pt] {$b$} (TL);

\draw[mid stealth]
    (BR) -- node[midway,right=4pt] {$b$} (TR);

% Interior edges and labels, directed outward from the center
\draw[mid stealth]
    (O) -- node[pos=0.5,below right=-3pt] {$e_1$} (BL);
\draw[mid stealth]
    (O) -- node[pos=0.5,above right=-3pt] {$e_2$} (BR);
\draw[mid stealth]
    (O) -- node[pos=0.5,above left=-3pt] {$e_3$} (TR);
\draw[mid stealth]
    (O) -- node[pos=0.5,below left=-3pt] {$e_4$} (TL);

% Region labels
\node at (2.5,1.5) {$T_1$};
\node at (3.5,2.5) {$T_2$};
\node at (2.5,3.5) {$T_3$};
\node at (1.5,2.5) {$T_4$};

% Black vertices
\node[vertex] at (BL) {};
\node[vertex] at (BR) {};
\node[vertex] at (TR) {};
\node[vertex] at (TL) {};
\node[vertex] at (O)  {};
